# src/response_processor.py
import json

def process_triage_response(raw_text: str, prompt_version: str) -> dict:
    try:
        result = json.loads(raw_text)
    except json.JSONDecodeError:
        return {"category": "UNKNOWN", "confidence": 0.0, "error": "parse_failure"}

    major = int(prompt_version.split(".")[0])

    if major == 1:
        # v1.x output: {"category": "BILLING", "confidence": 0.9}
        return {
            "category": result.get("category", "UNKNOWN"),
            "confidence": float(result.get("confidence", 0.0)),
            "subcategory": None,     # field added in v2, backfilled as None
        }
    elif major == 2:
        # v2.x output: {"category": "BILLING", "subcategory": "PAYMENT_FAILED", "confidence": 0.9}
        return result

    return result    # unknown major — pass through

